"use client";

import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

const BASE_URL = "http://localhost:5000";

const MyClaims = () => {
  const router = useRouter();
  const [MyClaims, setMyClaims] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMyClaims = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/user/myClaims`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to fetch messages");
        const data = await res.json();
        setMyClaims(data);
      } catch (err) {
        console.error("Message fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchMyClaims();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-[#F8FAFC] flex flex-col items-center justify-center">
        <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-500 font-medium tracking-tight font-sans">
          Syncing Claims...
        </p>
      </div>
    );
  }

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <h1 className="text-2xl font-bold mb-6">My Claims</h1>

      <div className="grid md:grid-cols-2 gap-6">
        {MyClaims.map((claim) => (
          <div
            key={claim._id}
            className="border rounded-xl p-4 shadow-sm bg-white"
          >
            {/* ITEM IMAGE */}
            {claim.itemId?.photos?.length > 0 && (
              <img
                src={claim.itemId.photos[0]}
                alt="item"
                className="w-full h-44 object-cover rounded-lg mb-3"
              />
            )}

            {/* ITEM INFO */}
            <h2 className="font-semibold text-lg">
              {claim.itemId?.title || "Untitled Item"}
            </h2>

            <p className="text-sm text-gray-600 mb-2">
              {claim.itemId?.description}
            </p>

            {/* STATUS */}
            <span
              className={`inline-block px-3 py-1 text-xs rounded-full font-medium mb-2 ${
                claim.status === "approved"
                  ? "bg-green-100 text-green-700"
                  : claim.status === "rejected"
                    ? "bg-red-100 text-red-700"
                    : "bg-yellow-100 text-yellow-700"
              }`}
            >
              {claim.status.toUpperCase()}
            </span>

            {/* PROOF */}
            <p className="mt-2 text-sm">
              <b>Proof:</b> {claim.proofDescription}
            </p>

            {/* POSTED BY */}
            <div className="mt-3 text-sm text-gray-700">
              <p>
                <b>Posted By:</b> {claim.postedBy?.name}
              </p>
              <p>{claim.postedBy?.email}</p>
            </div>

            {/* DATES */}
            <div className="mt-2 text-xs text-gray-500">
              <p>Created: {new Date(claim.createdAt).toLocaleDateString()}</p>

              {claim.reviewedAt && (
                <p>
                  Reviewed: {new Date(claim.reviewedAt).toLocaleDateString()}
                </p>
              )}
            </div>

            {/* DELETE */}
            <button
              onClick={() => deleteClaim(claim._id)}
              className="mt-4 w-full bg-red-500 hover:bg-red-600 text-white py-2 rounded-lg text-sm"
            >
              Delete Claim
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MyClaims;
